    fs::write(
        root_path.join("sub-01/ses-02/func/sub-01_ses-02_task-nback_run-2_bold.nii.gz"),
        b"dummy"
    ).unwrap();
    fs::write(
        root_path.join("sub-02/ses-01/func/sub-02_ses-01_task-rest_bold.nii.gz"),
