use bids_rust::{BidsProject, EventData, SidecarData, ConfoundData};
use std::fs;
use tempfile::TempDir;

fn create_test_project_with_data() -> (TempDir, BidsProject) {
    let temp_dir = TempDir::new().unwrap();
    let root_path = temp_dir.path();

    // Create dataset_description.json
    let dataset_desc = r#"{
        "Name": "IO Test Dataset",
        "BIDSVersion": "1.6.0"
    }"#;
    fs::write(root_path.join("dataset_description.json"), dataset_desc).unwrap();

    // Create directories
    fs::create_dir_all(root_path.join("sub-01/func")).unwrap();
    fs::create_dir_all(root_path.join("derivatives/fmriprep/sub-01/func")).unwrap();

    // Create event file
    let events_content = "onset\tduration\ttrial_type\tresponse_time\n\
        0.0\t2.0\tstimulus\t1.435\n\
        2.5\t2.0\tstimulus\t1.523\n\
        5.0\t1.5\tresponse\t0.987\n\
        8.0\t2.0\tstimulus\t1.612\n\
        10.5\t1.5\tresponse\t1.023\n";
    fs::write(
        root_path.join("sub-01/func/sub-01_task-stroop_events.tsv"),
        events_content
    ).unwrap();

    // Create JSON sidecar
    let sidecar_content = r#"{
        "RepetitionTime": 2.0,
        "EchoTime": 0.03,
        "FlipAngle": 90,
        "SliceTiming": [0.0, 0.5, 1.0, 1.5],
        "TaskName": "Stroop Task",
        "Instructions": "Respond to the color of the text",
        "CognitiveParadigm": "Stroop"
    }"#;
    fs::write(
        root_path.join("sub-01/func/sub-01_task-stroop_bold.json"),
        sidecar_content
    ).unwrap();

    // Create a functional scan file
    fs::write(
        root_path.join("sub-01/func/sub-01_task-stroop_bold.nii.gz"),
        b"dummy"
    ).unwrap();

    // Create confounds file
    let confounds_content = "trans_x\ttrans_y\ttrans_z\trot_x\trot_y\trot_z\tglobal_signal\tcsf\twhite_matter\n\
        0.01\t-0.02\t0.03\t0.001\t-0.002\t0.001\t100.5\t95.2\t98.7\n\
        0.02\t-0.01\t0.02\t0.002\t-0.001\t0.001\t101.2\t94.8\t99.1\n\
        0.01\t-0.03\t0.04\t0.001\t-0.003\t0.002\t99.8\t95.5\t98.5\n\
        0.03\t-0.02\t0.03\t0.003\t-0.002\t0.001\t100.9\t95.1\t99.0\n\
        0.02\t-0.01\t0.05\t0.002\t-0.001\t0.003\t101.5\t94.9\t98.8\n";
    fs::write(
        root_path.join("derivatives/fmriprep/sub-01/func/sub-01_task-stroop_desc-confounds_timeseries.tsv"),
        confounds_content
    ).unwrap();

    let project = BidsProject::new(root_path).unwrap();
    (temp_dir, project)
}

#[test]
fn test_read_event_file() {
    let (_temp_dir, project) = create_test_project_with_data();

    // Find event file
    let event_files = project.search_files()
        .suffix("events")
        .extension("tsv")
        .execute()
        .unwrap();

    assert_eq!(event_files.len(), 1);
    let event_file = &event_files[0];

    // Read event data
    let event_data = EventData::read(event_file.path.as_ref().unwrap()).unwrap();

    // Check basic fields
    assert_eq!(event_data.onset.len(), 5);
    assert_eq!(event_data.duration.len(), 5);
    assert_eq!(event_data.trial_type.len(), 5);

    // Check values
    assert_eq!(event_data.onset[0], 0.0);
    assert_eq!(event_data.onset[1], 2.5);
    assert_eq!(event_data.duration[0], 2.0);
    assert_eq!(event_data.trial_type[0], "stimulus");
    assert_eq!(event_data.trial_type[2], "response");

    // Check additional columns
    assert!(event_data.columns.contains_key("response_time"));
    let response_times = event_data.columns.get("response_time").unwrap();
    assert_eq!(response_times.len(), 5);
}

#[test]
fn test_read_json_sidecar() {
    let (_temp_dir, project) = create_test_project_with_data();

    // Find JSON file
    let json_files = project.search_files()
        .suffix("bold")
        .extension("json")
        .execute()
        .unwrap();

    assert_eq!(json_files.len(), 1);
    let json_file = &json_files[0];

    // Read sidecar data
    let sidecar = SidecarData::read(json_file.path.as_ref().unwrap()).unwrap();

    // Check fields
    assert_eq!(sidecar.repetition_time(), Some(2.0));
    assert_eq!(sidecar.echo_time(), Some(0.03));
    assert_eq!(sidecar.flip_angle(), Some(90.0));

    // Check string fields
    assert_eq!(sidecar.task_name(), Some("Stroop Task".to_string()));
    assert_eq!(sidecar.instructions(), Some("Respond to the color of the text".to_string()));

    // Check array fields
    let slice_timing = sidecar.slice_timing();
    assert!(slice_timing.is_some());
    let slice_timing = slice_timing.unwrap();
    assert_eq!(slice_timing.len(), 4);
    assert_eq!(slice_timing[0], 0.0);
    assert_eq!(slice_timing[3], 1.5);

    // Check custom field access
    let paradigm: Option<String> = sidecar.get_field("CognitiveParadigm");
    assert_eq!(paradigm, Some("Stroop".to_string()));
}

#[test]
fn test_read_confounds_file() {
    let (_temp_dir, project) = create_test_project_with_data();

    // Find confounds file
    let confound_files = project.search_files()
        .entity("desc", "confounds")
        .suffix("timeseries")
        .extension("tsv")
        .execute()
        .unwrap();

    assert_eq!(confound_files.len(), 1);
    let confound_file = &confound_files[0];

    // Read confound data
    let confounds = ConfoundData::read(confound_file.path.as_ref().unwrap()).unwrap();

    // Check dimensions
    assert_eq!(confounds.n_volumes(), 5);
    assert_eq!(confounds.n_confounds(), 9);

    // Check column names
    let columns = confounds.column_names();
    assert!(columns.contains(&"trans_x".to_string()));
    assert!(columns.contains(&"rot_z".to_string()));
    assert!(columns.contains(&"global_signal".to_string()));

    // Get specific columns
    let trans_x = confounds.get_column("trans_x").unwrap();
    assert_eq!(trans_x.len(), 5);
    assert!((trans_x[0] - 0.01).abs() < 1e-6);

    let global_signal = confounds.get_column("global_signal").unwrap();
    assert!((global_signal[0] - 100.5).abs() < 1e-6);

    // Get motion parameters
    let motion_params = confounds.get_motion_parameters();
    assert_eq!(motion_params.ncols(), 6); // trans_x/y/z, rot_x/y/z
    assert_eq!(motion_params.nrows(), 5); // 5 volumes

    // Check motion parameter values
    assert!((motion_params[(0, 0)] - 0.01).abs() < 1e-6); // trans_x[0]
    assert!((motion_params[(0, 3)] - 0.001).abs() < 1e-6); // rot_x[0]
}

#[test]
fn test_confounds_pca() {
    let (_temp_dir, project) = create_test_project_with_data();

    // Find and read confounds
    let confound_files = project.search_files()
        .entity("desc", "confounds")
        .execute()
        .unwrap();

    let confounds = ConfoundData::read(confound_files[0].path.as_ref().unwrap()).unwrap();

    // Perform PCA on motion parameters
    let pca_result = confounds.pca_motion(Some(2)).unwrap();

    // Check PCA results
    assert_eq!(pca_result.n_components, 2);
    assert_eq!(pca_result.components.nrows(), 5); // 5 volumes
    assert_eq!(pca_result.components.ncols(), 2); // 2 components

    // Check explained variance
    assert_eq!(pca_result.explained_variance.len(), 2);
    assert_eq!(pca_result.explained_variance_ratio.len(), 2);

    // Variance ratios should sum to <= 1.0
    let total_variance: f64 = pca_result.explained_variance_ratio.iter().sum();
    assert!(total_variance <= 1.0 + 1e-6);

    // First component should explain more variance than second
    assert!(pca_result.explained_variance_ratio[0] >= pca_result.explained_variance_ratio[1]);
}

#[test]
fn test_confounds_select_columns() {
    let (_temp_dir, project) = create_test_project_with_data();

    let confound_files = project.search_files()
        .entity("desc", "confounds")
        .execute()
        .unwrap();

    let confounds = ConfoundData::read(confound_files[0].path.as_ref().unwrap()).unwrap();

    // Select specific columns
    let selected = confounds.select_columns(&["trans_x", "trans_y", "global_signal"]);

    assert_eq!(selected.ncols(), 3);
    assert_eq!(selected.nrows(), 5);

    // Check values match
    let trans_x = confounds.get_column("trans_x").unwrap();
    assert!((selected[(0, 0)] - trans_x[0]).abs() < 1e-6);
}

