//! Example of PCA analysis on confound data
//! 
//! This example demonstrates how to:
//! - Find confound files in derivatives
//! - Read confound data
//! - Perform PCA on motion parameters
//! - Extract components for denoising

use bids_rust::{BidsProject, ConfoundData};
use std::env;
use std::path::Path;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Get dataset path from command line
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: {} <bids_dataset_path>", args[0]);
        eprintln!("\nThis example requires a dataset with fMRIPrep derivatives");
        return Ok(());
    }

    let dataset_path = Path::new(&args[1]);

    // Load the BIDS project
    println!("Loading BIDS dataset from: {}", dataset_path.display());
    let project = BidsProject::new(dataset_path)?;

    if !project.has_derivatives {
        eprintln!("Warning: No derivatives found in this dataset");
        eprintln!("This example works best with datasets processed by fMRIPrep");
    }

    // Find confound files
    println!("\n=== Finding Confound Files ===");
    let confound_files = project.search_files()
        .entity("desc", "confounds")
        .suffix("timeseries")
        .extension("tsv")
        .execute()?;

    if confound_files.is_empty() {
        eprintln!("No confound files found!");
        eprintln!("Make sure the dataset has been processed with fMRIPrep");
        return Ok(());
    }

    println!("Found {} confound files", confound_files.len());

    // Process each confound file
    for (i, confound_file) in confound_files.iter().enumerate() {
        if i >= 3 {
            println!("\n... processing {} more files", confound_files.len() - 3);
            break;
        }

        println!("\n=== Processing File {} ===", i + 1);
        println!("File: {}", confound_file.to_filename());

        if let Some(path) = &confound_file.path {
            // Read confound data
            let confounds = ConfoundData::read(path)?;

            println!("Dimensions: {} volumes × {} confounds", 
                confounds.n_volumes(), 
                confounds.n_confounds()
            );

            // List available columns
            let columns = confounds.column_names();
            println!("\nAvailable confounds: {} total", columns.len());

            // Show motion-related columns
            let motion_cols: Vec<_> = columns.iter()
                .filter(|c| c.starts_with("trans_") || c.starts_with("rot_"))
                .collect();

            if !motion_cols.is_empty() {
                println!("Motion parameters: {:?}", motion_cols);
            }

            // Perform PCA on motion parameters
            println!("\n--- PCA Analysis ---");

            // Try different numbers of components
            for n_components in [1, 2, 3] {
                match confounds.pca_motion(Some(n_components)) {
                    Ok(pca_result) => {
                        let total_variance: f64 = pca_result.explained_variance_ratio
                            .iter()
                            .sum::<f64>() * 100.0;

                        println!("\nPCA with {} component{}:",
                            n_components,
                            if n_components == 1 { "" } else { "s" }
                        );

                        for (j, var_ratio) in pca_result.explained_variance_ratio.iter().enumerate() {
                            println!("  Component {}: {:.1}% variance", 
                                j + 1, 
                                var_ratio * 100.0
                            );
                        }

                        println!("  Total variance explained: {:.1}%", total_variance);
                    }
                    Err(e) => {
                        eprintln!("  Error performing PCA: {}", e);
                    }
                }
            }

            // Find optimal number of components for 95% variance
            match confounds.pca_motion_variance(0.95) {
                Ok(pca_result) => {
                    println!("\nComponents needed for 95% variance: {}", 
                        pca_result.n_components
                    );

                    // Show component values for first few timepoints
                    println!("\nFirst 5 timepoints of components:");
                    let components = &pca_result.components;
                    for i in 0..5.min(components.nrows()) {
                        print!("  t={}: ", i);
                        for j in 0..components.ncols() {
                            print!("{:6.3} ", components[(i, j)]);
                        }
                        println!();
                    }
                }
                Err(e) => {
                    eprintln!("Error finding optimal components: {}", e);
                }
            }

            // Analyze other confounds
            println!("\n--- Other Confounds ---");

            // Check for CompCor components
            let compcor: Vec<_> = columns.iter()
                .filter(|c| c.contains("comp_cor"))
                .collect();

            if !compcor.is_empty() {
                println!("CompCor components: {} found", compcor.len());
            }

            // Check for global signals
            for signal in ["global_signal", "white_matter", "csf"] {
                if columns.contains(&signal.to_string()) {
                    if let Ok(values) = confounds.get_column(signal) {
                        let mean = values.iter().sum::<f64>() / values.len() as f64;
                        let std = {
                            let variance = values.iter()
                                .map(|v| (v - mean).powi(2))
                                .sum::<f64>() / values.len() as f64;
                            variance.sqrt()
                        };

                        println!("{}: mean={:.2}, std={:.2}", signal, mean, std);
                    }
                }
            }

            // Motion summary statistics
            if let Ok(motion_params) = confounds.get_motion_parameters() {
                println!("\n--- Motion Summary ---");

                // Calculate mean absolute displacement for each parameter
                for (j, param) in ["trans_x", "trans_y", "trans_z", "rot_x", "rot_y", "rot_z"]
                    .iter()
                    .enumerate() 
                {
                    if j < motion_params.ncols() {
                        let col = motion_params.column(j);
                        let mean_abs = col.iter()
                            .map(|v| v.abs())
                            .sum::<f64>() / col.len() as f64;

                        let unit = if param.starts_with("trans") { "mm" } else { "rad" };
                        println!("  {}: mean absolute = {:.4} {}", param, mean_abs, unit);
                    }
                }
            }
        }
    }

    println!("\n=== Analysis Complete ===");

    Ok(())
}

