//! Example for cross-validating results with R bidser package
//! 
//! This example shows how to:
//! - Export data in formats suitable for R comparison
//! - Generate validation reports
//! - Compare parsing results

use bids_rust::{BidsProject, parse_bids_filename, ConfoundData};
use std::env;
use std::path::Path;
use std::fs::File;
use std::io::Write;

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let args: Vec<String> = env::args().collect();
    if args.len() < 2 {
        eprintln!("Usage: {} <bids_dataset_path> [output_dir]", args[0]);
        eprintln!("\nThis will generate CSV files for comparison with R");
        return Ok(());
    }

    let dataset_path = Path::new(&args[1]);
    let output_dir = if args.len() > 2 {
        Path::new(&args[2])
    } else {
        Path::new("./validation_output")
    };

    // Create output directory
    std::fs::create_dir_all(output_dir)?;

    // Load project
    let project = BidsProject::new(dataset_path)?;
    println!("Loaded dataset: {}", project.name);

    // 1. Export basic project information
    println!("\n=== Exporting Project Info ===");
    let project_info_path = output_dir.join("project_info.csv");
    let mut file = File::create(&project_info_path)?;

    writeln!(file, "property,value")?;
    writeln!(file, "name,\"{}\"", project.name)?;
    writeln!(file, "path,\"{}\"", project.path.display())?;
    writeln!(file, "has_sessions,{}", project.has_sessions)?;
    writeln!(file, "has_derivatives,{}", project.has_derivatives)?;
    writeln!(file, "n_participants,{}", project.participants().len())?;
    writeln!(file, "n_sessions,{}", project.sessions().len())?;
    writeln!(file, "n_tasks,{}", project.tasks().len())?;

    println!("Written: {}", project_info_path.display());

    // 2. Export file listing
    println!("\n=== Exporting File List ===");
    let files = project.search_files().execute()?;
    let file_list_path = output_dir.join("file_list.csv");
    let mut file = File::create(&file_list_path)?;

    // Write header
    writeln!(file, "filename,subject,session,task,run,suffix,extension")?;

    for bids_file in &files {
        writeln!(file, "\"{}\",\"{}\",\"{}\",\"{}\",\"{}\",\"{}\",\"{}\"",
            bids_file.to_filename(),
            bids_file.entities.get("sub").unwrap_or(&String::new()),
            bids_file.entities.get("ses").unwrap_or(&String::new()),
            bids_file.entities.get("task").unwrap_or(&String::new()),
            bids_file.entities.get("run").unwrap_or(&String::new()),
            bids_file.suffix,
            bids_file.extension
        )?;
    }

    println!("Written: {} ({} files)", file_list_path.display(), files.len());

    // 3. Test filename parsing
    println!("\n=== Testing Filename Parsing ===");
    let test_filenames = vec![
        "sub-01_task-rest_bold.nii.gz",
        "sub-01_ses-pre_task-nback_run-1_bold.nii.gz",
        "sub-01_ses-01_T1w.nii.gz",
        "sub-01_task-rest_events.tsv",
        "sub-01_task-rest_desc-confounds_timeseries.tsv",
        "sub-01_space-MNI152NLin2009cAsym_desc-preproc_bold.nii.gz",
    ];

    let parsing_test_path = output_dir.join("parsing_test.csv");
    let mut file = File::create(&parsing_test_path)?;

    writeln!(file, "filename,parsed_successfully,error_message")?;

    for filename in test_filenames {
        match parse_bids_filename(filename) {
            Ok(_parsed) => {
                writeln!(file, "\"{}\",true,\"\"", filename)?;
            }
            Err(e) => {
                writeln!(file, "\"{}\",false,\"{}\"", filename, e)?;
            }
        }
    }

    println!("Written: {}", parsing_test_path.display());

    // 4. Export participant list
    println!("\n=== Exporting Participants ===");
    let participants_path = output_dir.join("participants_rust.csv");
    let mut file = File::create(&participants_path)?;

    writeln!(file, "participant_id")?;
    for participant in project.participants() {
        writeln!(file, "sub-{}", participant)?;
    }

    println!("Written: {}", participants_path.display());

    // 5. If confounds exist, export PCA results
    let confound_files = project.search_files()
        .entity("desc", "confounds")
        .suffix("timeseries")
        .execute()?;

    if !confound_files.is_empty() {
        println!("\n=== Exporting PCA Results ===");

        if let Some(confound_file) = confound_files.first() {
            if let Some(path) = &confound_file.path {
                let confounds = ConfoundData::read(path)?;

                // Perform PCA with 3 components
                if let Ok(pca_result) = confounds.pca_motion(Some(3)) {
                    let pca_path = output_dir.join("pca_results.csv");
                    let mut file = File::create(&pca_path)?;

                    // Write explained variance
                    writeln!(file, "component,explained_variance,explained_variance_ratio")?;
                    for (i, (var, ratio)) in pca_result.explained_variance.iter()
                        .zip(&pca_result.explained_variance_ratio)
                        .enumerate() 
                    {
                        writeln!(file, "{},{},{}", i + 1, var, ratio)?;
                    }

                    println!("Written: {}", pca_path.display());

                    // Write components
                    let components_path = output_dir.join("pca_components.csv");
                    let mut file = File::create(&components_path)?;

                    // Header
                    write!(file, "timepoint")?;
                    for i in 0..pca_result.n_components {
                        write!(file, ",PC{}", i + 1)?;
                    }
                    writeln!(file)?;

                    // Data
                    for i in 0..pca_result.components.nrows() {
                        write!(file, "{}", i)?;
                        for j in 0..pca_result.components.ncols() {
                            write!(file, ",{}", pca_result.components[(i, j)])?;
                        }
                        writeln!(file)?;
                    }

                    println!("Written: {}", components_path.display());
                }
            }
        }
    }

    // 6. Generate R script for comparison
    println!("\n=== Generating R Comparison Script ===");
    let r_script_path = output_dir.join("compare_with_bidser.R");
    let mut file = File::create(&r_script_path)?;

    writeln!(file, r#"# R script to compare with bidser output
library(bidser)
library(tidyverse)

# Load the dataset
dataset_path <- "{}"
proj <- bids_project(dataset_path)

# Export project info
project_info_r <- tibble(
  property = c("name", "has_sessions", "has_derivatives", 
               "n_participants", "n_sessions", "n_tasks"),
  value = c(proj$name, 
            !is.null(proj$sessions), 
            has_derivatives(proj),
            length(participants(proj)),
            length(sessions(proj)),
            length(tasks(proj)))
)

write_csv(project_info_r, "project_info_r.csv")

# Export participant list
participants_r <- tibble(
  participant_id = participants(proj)
)
write_csv(participants_r, "participants_r.csv")

# Compare with Rust output
rust_info <- read_csv("project_info.csv")
r_info <- read_csv("project_info_r.csv")

cat("\n=== Project Info Comparison ===\n")
comparison <- full_join(
  rust_info %>% rename(rust_value = value),
  r_info %>% rename(r_value = value),
  by = "property"
)
print(comparison)

# Compare participants
rust_participants <- read_csv("participants_rust.csv")
r_participants <- read_csv("participants_r.csv")

cat("\n=== Participant Comparison ===\n")
cat("Rust participants:", nrow(rust_participants), "\n")
cat("R participants:", nrow(r_participants), "\n")
cat("Matching:", all(rust_participants$participant_id %in% r_participants$participant_id), "\n")

# If you have confounds, compare PCA
if (file.exists("pca_results.csv")) {{
  cat("\n=== PCA Comparison ===\n")
  cat("To compare PCA results, run process_confounds() on the same file\n")
  cat("and compare explained variance ratios\n")
}}

cat("\nComparison complete!\n")
"#, dataset_path.display())?;

    println!("Written: {}", r_script_path.display());

    println!("\n=== Validation Files Generated ===");
    println!("Output directory: {}", output_dir.display());
    println!("\nTo compare with R:");
    println!("1. Run R in the output directory");
    println!("2. Execute: source('compare_with_bidser.R')");
    println!("3. Compare the generated CSV files");

    Ok(())
}

